const codigo = $json.codigo_TH;

if (!codigo) {
  return [{ json: { erro: "SEM_CODIGO_VALIDO" } }];
}

const match = codigo.match(/^([A-Za-z]+)(\d+)$/);
if (!match) {
  return [{ json: { erro: "FORMATO_INVALIDO" } }];
}

const prefixo = match[1];
const numeroAtual = parseInt(match[2], 10);

const novoNumero = numeroAtual + 1;

const tamanhoNumero = match[2].length;
const novoNumeroFormatado = String(novoNumero).padStart(tamanhoNumero, '0');

return [{ json: { novo_codigo: `${prefixo}${novoNumeroFormatado}` } }];

